ability_entry(aftermath, generation_iv, true, 'Damages the attacker for 1/4 its max HP when knocked out by a contact move.', 'When this Pokémon is knocked out by a move that makes contact, the move''s user takes 1/4 its maximum HP in damage.').
ability_entry(air_lock, generation_iii, true, 'Negates all effects of weather, but does not prevent the weather itself.', 'While this Pokémon is in battle, weather can still be in play, but will not have any of its effects. This ability functions identically to cloud nine.').
