ability_entry(earth_eater, generation_ix, true, 'Restores HP when hit by a Ground-type move.', 'If hit by a Ground-type move, the Pokémon has its HP restored instead of taking damage.').
ability_entry(effect_spore, generation_iii, true, 'Has a 30% chance of inflcting either paralysis, poison, or sleep on attacking Pokémon on contact.', 'Whenever a move makes contact with this Pokémon, the move''s user has a 30% chance of being paralyzed, poisoned, or put to sleep, chosen at random. Nothing is done to compensate if the move''s user is immune to one of these ailments; there is simply a lower chance that the move''s user will be affected.').
