ability_entry(healer, generation_v, true, 'Has a 30% chance of curing each adjacent ally of any major status ailment after each turn.', 'Friendly Pokémon next to this Pokémon in double and triple battles each have a 30% chance of being cured of any major status ailment after each turn.').
